package com.secman.domain

import io.micronaut.serde.annotation.Serdeable
import org.hibernate.annotations.JdbcTypeCode
import org.hibernate.type.SqlTypes
import jakarta.persistence.*
import jakarta.validation.constraints.Email
import jakarta.validation.constraints.NotBlank
import jakarta.validation.constraints.Pattern
import java.time.Instant

/**
 * UserMapping entity - stores mappings between user emails, AWS account IDs, domains, and IP addresses
 *
 * Features: 013-user-mapping-upload, 020-i-want-to (IP address mapping), 042-future-user-mappings
 * Purpose: Enable role-based access control across multiple AWS accounts, domains, and IP addresses
 * Now supports future user mappings - mappings for users who don't yet exist in the system
 *
 * Business Rules:
 * - Email is REQUIRED
 * - At least one of AWS Account ID, Domain, or IP Address must be provided
 * - One email can map to multiple AWS accounts (many-to-many)
 * - One email can map to multiple domains (many-to-many)
 * - One email can map to multiple IP addresses/ranges (many-to-many)
 * - Unique constraint on (email, awsAccountId, domain, ipAddress) prevents duplicates
 * - Email and domain are normalized to lowercase for case-insensitive matching
 * - AWS account IDs must be exactly 12 numeric digits when provided
 * - IP addresses support three formats: single (192.168.1.100), CIDR (192.168.1.0/24), dash range (192.168.1.1-192.168.1.100)
 * - User reference is nullable - allows future user mappings (Feature 042)
 * - AppliedAt tracks when future user mapping was applied to a user (Feature 042)
 *
 * Example Mappings:
 * - john@example.com → 123456789012 → null → null (email + AWS account only)
 * - john@example.com → null → example.com → null (email + domain only)
 * - john@example.com → null → null → 192.168.1.0/24 (email + IP range)
 * - john@example.com → 123456789012 → example.com → 192.168.1.0/24 (email + AWS + domain + IP)
 * - future@example.com → 123456789012 → null → null + user=null + appliedAt=null (future user mapping)
 *
 * Related to: Feature 013 (User Mapping Upload), Feature 020 (IP Address Mapping), Feature 042 (Future User Mappings)
 */
@Entity
@Table(
    name = "user_mapping",
    uniqueConstraints = [
        UniqueConstraint(
            name = "uk_user_mapping_composite",
            columnNames = ["email", "aws_account_id", "domain", "ip_address"]
        )
    ],
    indexes = [
        Index(name = "idx_user_mapping_email", columnList = "email"),
        Index(name = "idx_user_mapping_aws_account", columnList = "aws_account_id"),
        Index(name = "idx_user_mapping_domain", columnList = "domain"),
        Index(name = "idx_user_mapping_email_aws", columnList = "email,aws_account_id"),
        Index(name = "idx_user_mapping_ip_address", columnList = "ip_address"),
        Index(name = "idx_user_mapping_ip_range", columnList = "ip_range_start,ip_range_end"),
        Index(name = "idx_user_mapping_email_ip", columnList = "email,ip_address"),
        Index(name = "idx_user_mapping_applied_at", columnList = "applied_at"), // Feature 042: Efficient filtering for Current vs Applied History tabs
        Index(name = "idx_user_mapping_status", columnList = "status"), // Feature 049: Status filtering
        Index(name = "idx_user_mapping_email_status", columnList = "email,status") // Feature 049: User + status queries
    ]
)
@Serdeable
data class UserMapping(
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    var id: Long? = null,

    @Column(nullable = false, length = 255)
    @Email(message = "Invalid email format")
    @NotBlank(message = "Email address is required")
    var email: String,

    // Feature 042: User reference (nullable for future user mappings)
    @ManyToOne(fetch = FetchType.LAZY, optional = true)
    @JoinColumn(name = "user_id", nullable = true)
    var user: User? = null,

    // Feature 042: Timestamp when mapping was applied to user (null = not yet applied)
    @Column(name = "applied_at", nullable = true)
    var appliedAt: Instant? = null,

    @Column(name = "aws_account_id", nullable = true, length = 12)
    @Pattern(regexp = "^\\d{12}$", message = "AWS Account ID must be exactly 12 numeric digits")
    var awsAccountId: String?,

    @Column(nullable = true, length = 255)
    @Pattern(regexp = "^[a-zA-Z0-9.-]+$", message = "Domain must contain only letters, numbers, dots, and hyphens")
    var domain: String?,

    // IP Address Mapping Fields (Feature 020)
    @Column(name = "ip_address", nullable = true, length = 100)
    var ipAddress: String? = null,

    @Column(name = "ip_range_type", nullable = true, length = 20)
    @JdbcTypeCode(SqlTypes.VARCHAR)
    @Enumerated(EnumType.STRING)
    var ipRangeType: IpRangeType? = null,

    @Column(name = "ip_range_start", nullable = true)
    var ipRangeStart: Long? = null,

    @Column(name = "ip_range_end", nullable = true)
    var ipRangeEnd: Long? = null,

    @Column(name = "created_at", updatable = false)
    var createdAt: Instant? = null,

    @Column(name = "updated_at")
    var updatedAt: Instant? = null,

    // Feature 049: Status tracking for pending vs active mappings
    @Column(name = "status", nullable = false, length = 20)
    @JdbcTypeCode(SqlTypes.VARCHAR)
    @Enumerated(EnumType.STRING)
    var status: MappingStatus = MappingStatus.ACTIVE
) {
    /**
     * Lifecycle callback - executed before entity is persisted to database
     * Normalizes email and domain to lowercase, trims whitespace,
     * and coerces "no value" sentinels (e.g. "-none-", "none", "null") in
     * `domain` to SQL NULL so logically-equivalent rows hit the same unique
     * key. Without this, Cloud Custodian-style imports that use `-none-` as
     * a placeholder created a second row per AWS account that the dedup
     * checks could not collapse against the real-NULL row.
     */
    @PrePersist
    fun onCreate() {
        val now = Instant.now()
        createdAt = now
        updatedAt = now
        // Normalize email and domain to lowercase for case-insensitive matching
        email = email.lowercase().trim()
        domain = normalizeNullSentinel(domain?.lowercase()?.trim())
        awsAccountId = awsAccountId?.trim()

        // Feature 049: Set status based on user existence
        // PENDING if user is null (future user mapping), ACTIVE otherwise
        if (user == null && status == MappingStatus.ACTIVE) {
            status = MappingStatus.PENDING
        }
    }

    /**
     * Lifecycle callback - executed before entity is updated in database
     * Updates the updatedAt timestamp
     */
    @PreUpdate
    fun onUpdate() {
        updatedAt = Instant.now()
    }

    /**
     * Feature 042: Returns true if this is a future user mapping (not yet applied)
     * A future mapping has no user reference and no appliedAt timestamp
     */
    fun isFutureMapping(): Boolean {
        return user == null && appliedAt == null
    }

    /**
     * Feature 042: Returns true if this is an applied historical mapping
     * An applied mapping has an appliedAt timestamp (regardless of user reference)
     */
    fun isAppliedMapping(): Boolean {
        return appliedAt != null
    }

    override fun toString(): String {
        return "UserMapping(id=$id, email='$email', awsAccountId='$awsAccountId', domain='$domain', ipAddress='$ipAddress', ipRangeType=$ipRangeType)"
    }

    override fun equals(other: Any?): Boolean {
        if (this === other) return true
        if (other !is UserMapping) return false
        return id != null && id == other.id
    }

    override fun hashCode(): Int {
        return id?.hashCode() ?: 0
    }

    companion object {
        // Sentinel strings imported from source files (Cloud Custodian, ad-hoc CSVs)
        // that mean "no value" rather than a real domain. Compared after
        // lowercase()+trim().
        private val NULL_SENTINELS: Set<String> = setOf(
            "", "-", "--", "-none-", "none", "null", "nil", "n/a", "na"
        )

        /**
         * Coerces a "no value" sentinel string to SQL NULL.
         * Pass an already-trimmed, lowercased value (or null). Returns the
         * original value if it is a real domain, or null if it is a sentinel.
         */
        fun normalizeNullSentinel(value: String?): String? {
            if (value == null) return null
            return if (value in NULL_SENTINELS) null else value
        }
    }
}

package com.secman.controller

import com.secman.domain.User
import com.secman.dto.CreateUserMappingRequest
import com.secman.dto.UpdateUserMappingRequest
import com.secman.dto.UserMappingResponse
import com.secman.repository.UserRepository
import com.secman.service.UserMappingService
import io.micronaut.data.model.Pageable
import io.micronaut.http.HttpResponse
import io.micronaut.http.HttpStatus
import io.micronaut.http.MediaType
import io.micronaut.http.annotation.*
import io.micronaut.security.annotation.Secured
import io.micronaut.security.rules.SecurityRule
import io.micronaut.serde.annotation.Serdeable
import jakarta.transaction.Transactional
import jakarta.validation.constraints.*
import jakarta.validation.Valid
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder
import java.io.StringWriter
import java.time.LocalDate
import java.time.format.DateTimeFormatter

@Controller("/api/users")
@Secured("ADMIN")
open class UserController(
    private val userRepository: UserRepository,
    private val userDeletionValidator: com.secman.service.UserDeletionValidator,
    private val workgroupRepository: com.secman.repository.WorkgroupRepository,
    private val userMappingService: UserMappingService,
    private val adminNotificationService: com.secman.service.AdminNotificationService,
    private val userService: com.secman.service.UserService
) {

    private val passwordEncoder = BCryptPasswordEncoder()

    @Serdeable
    data class CreateUserRequest(
        @field:NotBlank @field:Size(min = 2, max = 100) val username: String,
        @field:NotBlank @field:Email @field:Size(max = 255) val email: String,
        @field:NotBlank @field:Size(min = 8, max = 200) val password: String,
        val roles: List<String>? = null,
        val workgroupIds: List<Long>? = null,
        val mfaEnabled: Boolean? = null
    )

    @Serdeable
    data class UpdateUserRequest(
        @field:Size(min = 2, max = 100) val username: String? = null,
        @field:Email @field:Size(max = 255) val email: String? = null,
        @field:Size(min = 8, max = 200) val password: String? = null,
        val roles: List<String>? = null,
        val workgroupIds: List<Long>? = null,
        val mfaEnabled: Boolean? = null
    )

    @Serdeable
    data class UserResponse(
        val id: Long,
        val username: String,
        val email: String,
        val roles: List<String>,
        val mfaEnabled: Boolean,
        val createdAt: String?,
        val updatedAt: String?,
        val lastLogin: String?,
        val workgroups: List<WorkgroupSummary>? = null,
        val workgroupCount: Int? = null
    ) {
        companion object {
            fun from(user: User, includeWorkgroups: Boolean = false): UserResponse {
                return UserResponse(
                    id = user.id!!,
                    username = user.username,
                    email = user.email,
                    roles = user.roles.map { it.name },
                    mfaEnabled = user.mfaEnabled,
                    createdAt = user.createdAt?.toString(),
                    updatedAt = user.updatedAt?.toString(),
                    lastLogin = user.lastLogin?.toString(),
                    workgroups = if (includeWorkgroups) {
                        user.workgroups.map { WorkgroupSummary(it.id!!, it.name) }
                    } else null,
                    workgroupCount = if (includeWorkgroups) user.workgroups.size else null
                )
            }
        }
    }

    @Serdeable
    data class WorkgroupSummary(
        val id: Long,
        val name: String
    )

    /**
     * List all users with optional workgroup information
     * Feature: 008-create-an-additional (Workgroup-Based Access Control)
     *
     * GET /api/users?includeWorkgroups=true
     * FR-010: Display user workgroup membership in admin views
     */
    @Get
    fun list(@QueryValue(defaultValue = "false") includeWorkgroups: Boolean): HttpResponse<List<UserResponse>> {
        val users = if (includeWorkgroups) {
            userRepository.findAllWithWorkgroups().map { UserResponse.from(it, true) }
        } else {
            userRepository.findAll().map { UserResponse.from(it, false) }
        }
        return HttpResponse.ok(users)
    }

    /**
     * Export all user email addresses as a CSV file.
     *
     * Inherits ADMIN authorization from the class-level @Secured("ADMIN").
     * Returns a CSV with two columns (Username, Email), one row per user.
     * Fields are sanitized to prevent CSV formula injection (CWE-1236).
     */
    @Get("/export/emails")
    @Produces(MediaType.TEXT_CSV)
    fun exportEmails(): HttpResponse<String> {
        val users = userRepository.findAll()

        val writer = StringWriter()
        writer.append("Username,Email\n")
        users.forEach { user ->
            writer.append("\"${sanitizeCsvField(user.username)}\",")
            writer.append("\"${sanitizeCsvField(user.email)}\"\n")
        }

        val timestamp = LocalDate.now().format(DateTimeFormatter.ISO_LOCAL_DATE)
        val filename = "secman-user-emails-$timestamp.csv"

        return HttpResponse.ok(writer.toString())
            .header("Content-Disposition", "attachment; filename=\"$filename\"")
    }

    /**
     * Sanitize CSV field to prevent formula injection attacks (CWE-1236).
     * Prefixes formula-triggering characters with a single quote so spreadsheet
     * programs (Excel/LibreOffice) treat them as text instead of executing them.
     */
    private fun sanitizeCsvField(value: String): String {
        if (value.isEmpty()) return ""
        val trimmed = value.trim()
        val quotesEscaped = trimmed.replace("\"", "\"\"")
        return if (trimmed.startsWith("=") ||
            trimmed.startsWith("+") ||
            trimmed.startsWith("-") ||
            trimmed.startsWith("@") ||
            trimmed.startsWith("|") ||
            trimmed.startsWith("%") ||
            trimmed.startsWith("\t") ||
            trimmed.startsWith("\r")
        ) {
            "'" + quotesEscaped
        } else {
            quotesEscaped
        }
    }

    @Post
    @Transactional
    open fun create(@Valid @Body request: CreateUserRequest, authentication: io.micronaut.security.authentication.Authentication): HttpResponse<*> {
        // Validation
        if (request.username.isBlank() || request.email.isBlank() || request.password.isBlank()) {
            return HttpResponse.badRequest(mapOf("error" to "Username, email, and password are required"))
        }

