    /**
     * GET /api/aws-account-sharing/users - Lightweight user list for the sharing form.
     *
     * Returns minimal user info for populating source/target dropdowns. Includes:
     *  - All existing Users (isPending = false)
     *  - Emails known only via PENDING UserMappings (users recorded in AWS
     *    account or domain mappings but who have never logged in).
     *    For these entries `id = null`, `isPending = true`, and the UI must
     *    submit them by email — the backend will create the User record on
     *    rule creation so the FK constraint is satisfied.
     *
     * Available to all authenticated users.
     */
    @Get("/users")
    fun listUsersForSharing(): HttpResponse<List<SharingUserResponse>> {
        val activeUsers = userRepository.findAll().map { user ->
            SharingUserResponse(
                id = user.id,
                username = user.username,
                email = user.email,
                isPending = false
            )
        }
        val activeEmails = activeUsers.mapNotNull { it.email.lowercase().takeIf { e -> e.isNotBlank() } }.toHashSet()

        // Distinct emails from PENDING mappings that don't already correspond to a real User.
        // findByStatus(PENDING) reliably lists mappings with no user_id link.
        val pendingEntries = userMappingRepository.findByStatus(MappingStatus.PENDING)
            .asSequence()
            .map { it.email.trim() }
            .filter { it.isNotEmpty() }
            .distinctBy { it.lowercase() }
            .filter { it.lowercase() !in activeEmails }
            .map { email ->
                SharingUserResponse(
                    id = null,
                    username = email.substringBefore("@").ifBlank { email },
                    email = email,
                    isPending = true
                )
            }
            .toList()

        val combined = (activeUsers + pendingEntries).sortedBy { it.email.lowercase() }
        return HttpResponse.ok(combined)
    }

    /**
     * View-all access — ADMIN or SECCHAMPION.
     * Allowed to see every sharing rule in the system.
     * All other authenticated users (including VULN) see only rules where they
     * are source OR target — handled via listSharingRulesForInvolvedUser.
     */
    private fun hasFullViewAccess(authentication: Authentication): Boolean {
        return authentication.roles.contains("ADMIN") ||
            authentication.roles.contains("SECCHAMPION")
    }

    /**
     * Manage-any access — ADMIN or SECCHAMPION.
     * Allowed to create rules with any sourceUserId and delete any rule.
     * Other authenticated users (including VULN) can only create rules with
     * themselves as the source and delete rules they own.
     */
    private fun hasFullManagementAccess(authentication: Authentication): Boolean {
        return authentication.roles.contains("ADMIN") ||
            authentication.roles.contains("SECCHAMPION")
    }

    @Serdeable
    data class SharingUserResponse(
        // null for pending users — the client must submit them by email and
        // the backend lazily creates a User record when a sharing rule is saved.
        val id: Long?,
        val username: String,
        val email: String,
        val isPending: Boolean = false
    )
}

 * Resolve a User from either an id or an email.
 *
 * - If `userId` is provided, look it up directly.
 * - If only `email` is provided, look up by email (case-insensitive). If no
 *   matching User exists (the email belongs to a "pending" mapping for a
 *   user who has never logged in), create a User record on the fly so that
 *   the sharing rule's FK is satisfied. The new User follows the OAuth
 *   auto-provisioning shape: no usable password, OAUTH auth source,
 *   default roles. Any PENDING UserMappings for the email are applied
 *   synchronously inside the current transaction — see the inline
 *   comment below for why we don't publish UserCreatedEvent here.
 *
 * @param side "source" or "target" — used only in error messages.
 */
private fun resolveUser(userId: Long?, email: String?, side: String): User {
    if (userId != null && userId > 0) {
        return userRepository.findById(userId)
            .orElseThrow { NoSuchElementException("$side user not found: $userId") }
    }
    val normalizedEmail = email?.trim()?.takeIf { it.isNotEmpty() }
        ?: throw IllegalArgumentException("$side user identifier required (id or email)")

    val existing = userRepository.findByEmailIgnoreCase(normalizedEmail).orElse(null)
    if (existing != null) return existing

    log.info("Creating pending User record on demand for {} email: {}", side, normalizedEmail)
    val username = resolveUniqueUsername(normalizedEmail.substringBefore("@"))
    val newUser = User(
        username = username,
        email = normalizedEmail,
        passwordHash = passwordEncoder.encode(UUID.randomUUID().toString())!!,
        roles = mutableSetOf(User.Role.USER, User.Role.VULN, User.Role.REQ),
        authSource = User.AuthSource.OAUTH
    )
    val saved = userRepository.save(newUser)

    // Apply PENDING UserMappings synchronously in the current transaction.
    //
    // We deliberately do NOT publish UserCreatedEvent here: the default
    // listener (UserMappingService.onUserCreated) is @Async @Transactional,
    // which opens a SEPARATE Hibernate session while ours still owns the
    // new User's `workgroups` PersistentSet. That cross-session collection
    // ownership trips Hibernate's "Found shared references to a collection"
    // check during auto-flush of the listener's first query. Performing the
    // mapping application in this thread and session avoids the hazard —
    // everything the async listener would have done, done synchronously.
    try {
        val applied = userMappingService.applyFutureUserMapping(saved)
        if (applied > 0) {
            log.info("Applied {} pending user mapping(s) to newly-created user: {}", applied, saved.email)
        }
    } catch (e: Exception) {
        // Don't fail sharing-rule creation if mapping application fails.
        log.warn("Failed to apply pending user mappings for {}: {}", saved.email, e.message)
    }
    return saved
}

