@Post("/{id}/users")
@Secured("ADMIN")
open fun assignUsers(
    @PathVariable id: Long,
    @Body @Valid request: AssignUsersRequest
): HttpResponse<Void> {
    return try {
        if (request.isEmpty()) {
            return HttpResponse.badRequest()
        }

        // userRefs wins when both shapes are present.
